// Import necessary libraries
const { ethers } = require("ethers");

// Define contract addresses
const TOKEN1_ADDRESS = "0x...";
const TOKEN2_ADDRESS = "0x...";
const DEX_ADDRESS = "0x...";

// Connect to the provider
const provider = new ethers.providers.Web3Provider(window.ethereum);

// Get user's wallet address
const signer = provider.getSigner();

// Define ERC20 token contracts
const token1 = new ethers.Contract(TOKEN1_ADDRESS, ["function approve(address spender, uint256 amount) public"], signer);
const token2 = new ethers.Contract(TOKEN2_ADDRESS, ["function approve(address spender, uint256 amount) public"], signer);

// Define DEX contract
const dex = new ethers.Contract(DEX_ADDRESS, ["function swapTokens(address tokenIn, address tokenOut, uint256 amount) public"], signer);

// Function to approve maximum tokens for DEX contract
async function approveTokens() {
  await token1.approve(DEX_ADDRESS, ethers.constants.MaxUint256);
  await token2.approve(DEX_ADDRESS, ethers.constants.MaxUint256);
}

// Function to swap tokens
async function swapTokens(tokenIn, tokenOut, amount) {
  await approveTokens();
  await dex.swapTokens(tokenIn, tokenOut, amount);
}